public void testIntCollectionAddAllAtEnd() {
    // make a SetUniqueList with two elements
    List list = new SetUniqueList(new ArrayList(), new HashSet());
    final Integer firstElement = new Integer(1);
    final Integer secondElement = new Integer(2);
    list.add(firstElement);
    list.add(secondElement);

    // add two new unique elements at the end (index 2)
    final Integer thirdElement = new Integer(3);
    final Integer fourthElement = new Integer(4);
    Collection collection = Arrays.asList(new Integer[] {thirdElement, fourthElement});
    list.addAll(2, collection);
    assertEquals("Unique elements should be added at end.", 4, list.size());
    assertEquals("First element should remain at index 0", firstElement, list.get(0));
    assertEquals("Second element should remain at index 1", secondElement, list.get(1));
    assertEquals("Third element should be at index 2", thirdElement, list.get(2));
    assertEquals("Fourth element should be at index 3", fourthElement, list.get(3));
}

public void testIntCollectionAddAllMiddleWithDuplicates() {
    // make a SetUniqueList with three elements
    List list = new SetUniqueList(new ArrayList(), new HashSet());
    final Integer firstElement = new Integer(1);
    final Integer secondElement = new Integer(2);
    final Integer thirdElement = new Integer(3);
    list.add(firstElement);
    list.add(secondElement);
    list.add(thirdElement);

    // add at index 1: one duplicate and one new element
    final Integer newElement = new Integer(4);
    Collection collection = Arrays.asList(new Integer[] {firstElement, newElement, secondElement});
    list.addAll(1, collection);
    assertEquals("Only unique element should be added.", 4, list.size());
    assertEquals("First element should remain at index 0", firstElement, list.get(0));
    assertEquals("New element should be at index 1", newElement, list.get(1));
    assertEquals("Second element should be at index 2", secondElement, list.get(2));
    assertEquals("Third element should be at index 3", thirdElement, list.get(3));
}

public void testIntCollectionAddAllEmptyCollection() {
    // make a SetUniqueList with one element
    List list = new SetUniqueList(new ArrayList(), new HashSet());
    final Integer element = new Integer(1);
    list.add(element);

    // add empty collection at index 0
    Collection collection = new ArrayList();
    boolean changed = list.addAll(0, collection);
    assertEquals("Size should remain unchanged.", 1, list.size());
    assertEquals("Element should remain at index 0", element, list.get(0));
    assertFalse("addAll should return false for empty collection.", changed);
}

public void testIntCollectionAddAllOnlyDuplicates() {
    // make a SetUniqueList with two elements
    List list = new SetUniqueList(new ArrayList(), new HashSet());
    final Integer firstElement = new Integer(1);
    final Integer secondElement = new Integer(2);
    list.add(firstElement);
    list.add(secondElement);

    // try to add only duplicates at index 1
    Collection collection = Arrays.asList(new Integer[] {firstElement, secondElement});
    boolean changed = list.addAll(1, collection);
    assertEquals("Size should remain unchanged.", 2, list.size());
    assertEquals("First element should remain at index 0", firstElement, list.get(0));
    assertEquals("Second element should remain at index 1", secondElement, list.get(1));
    assertFalse("addAll should return false when no elements added.", changed);
}
